DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGchoicemacros.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z'); Context()->variables->are($var => 'Real'); ($a, $b) = (1..20)[NchooseK(20,2)]; $b = random(0,1) ? $b : -$b; $left = Formula("$var + $a")->reduce; $right = Formula("$b")->reduce; Context("FiniteSolutionSets"); Context()->variables->are($var => 'Real'); $solution = $b - $a; $solset = Formula("{$solution}");
############################################################ # Body ############################################################
BEGIN_PGML Solve the equation.
[`[$left]=[$right]`]
[_]{$solset}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The opposite action to addition is subtraction.
[```\newcommand{\subtractright}[1]{{\highlight{{{}-#1}}}}\newcommand{\amp}{&} \begin{aligned} [$left] \amp= [$right]\\ [$left]\subtractright{[$a]} \amp= [$right]\subtractright{[$a]}\\ [$var] \amp= [$solution] \end{aligned} ```]
The solution set is [`[$solset]\text{.}`]
END_PGML_SOLUTION
